<?php
declare(strict_types=1);
require_once dirname(__DIR__).'/functions.php';
$admin=require_admin();if($admin['role']!=='superadmin'){http_response_code(403);exit('Только главный администратор.');}
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$action=(string)($_POST['action']??'');try{if($action==='create'){$username=trim((string)$_POST['username']);$password=(string)$_POST['password'];$role=(string)$_POST['role'];if(!preg_match('/^[a-zA-Z0-9_.-]{3,40}$/',$username)||strlen($password)<10||!in_array($role,['superadmin','manager','observer'],true))throw new RuntimeException('Проверьте логин, пароль и роль.');$st=db()->prepare('INSERT INTO admins(username,password_hash,role) VALUES(?,?,?)');$st->execute([$username,password_hash($password,PASSWORD_DEFAULT),$role]);audit_log('admin_created','admin',(int)db()->lastInsertId(),['username'=>$username,'role'=>$role]);flash('success','Администратор создан.');}elseif($action==='update'){$id=(int)$_POST['id'];$role=(string)$_POST['role'];if($id===(int)$admin['id']&&$role!=='superadmin')throw new RuntimeException('Нельзя понизить собственную роль.');db()->prepare('UPDATE admins SET role=? WHERE id=?')->execute([$role,$id]);audit_log('admin_role_updated','admin',$id,['role'=>$role]);flash('success','Роль изменена.');}elseif($action==='toggle'){$id=(int)$_POST['id'];if($id===(int)$admin['id'])throw new RuntimeException('Нельзя отключить собственную учётную запись.');db()->prepare('UPDATE admins SET is_active=CASE is_active WHEN 1 THEN 0 ELSE 1 END WHERE id=?')->execute([$id]);audit_log('admin_toggled','admin',$id);flash('success','Статус изменён.');}elseif($action==='password'){$id=(int)$_POST['id'];$password=(string)$_POST['password'];if(strlen($password)<10)throw new RuntimeException('Пароль — минимум 10 символов.');db()->prepare('UPDATE admins SET password_hash=? WHERE id=?')->execute([password_hash($password,PASSWORD_DEFAULT),$id]);audit_log('admin_password_reset','admin',$id);flash('success','Пароль изменён.');}}catch(Throwable $e){flash('error',$e instanceof PDOException?'Логин уже занят.':$e->getMessage());}redirect('admins.php');}
$admins=db()->query('SELECT * FROM admins ORDER BY id')->fetchAll();$pageTitle='Администраторы';$isAdminArea=true;require dirname(__DIR__).'/partials/header.php';
?>
<section class="section"><div class="container"><div class="dashboard-heading"><div><span class="kicker">Роли и доступ</span><h1>Администраторы</h1><p class="lead">Главный администратор — полный доступ; менеджер — кампании и данные; наблюдатель — только отчёты и журнал.</p></div></div><div class="admin-grid admin-grid-equal"><section class="panel"><h2>Добавить администратора</h2><form method="post" class="form-grid"><?=csrf_field()?><input type="hidden" name="action" value="create"><label>Логин<input name="username" required></label><label>Пароль<input type="password" name="password" minlength="10" required></label><label>Роль<select name="role"><option value="manager">Менеджер</option><option value="observer">Наблюдатель</option><option value="superadmin">Главный администратор</option></select></label><button class="button primary">Создать</button></form></section><section class="panel"><h2>Матрица прав</h2><ul class="program-list large-list"><li>Главный: все функции, резервные копии и администраторы</li><li>Менеджер: ученики, кандидаты, кампании, экспорт</li><li>Наблюдатель: обзор, отчёты и аудит без изменений</li></ul></section></div><section class="panel"><div class="table-wrap"><table><thead><tr><th>Логин</th><th>Роль</th><th>Статус</th><th>Последний вход</th><th>Действия</th></tr></thead><tbody><?php foreach($admins as $a):?><tr><td><strong><?=e($a['username'])?></strong></td><td><form method="post" class="inline-row-form"><?=csrf_field()?><input type="hidden" name="action" value="update"><input type="hidden" name="id" value="<?=(int)$a['id']?>"><select name="role"><option value="superadmin" <?=$a['role']==='superadmin'?'selected':''?>>Главный</option><option value="manager" <?=$a['role']==='manager'?'selected':''?>>Менеджер</option><option value="observer" <?=$a['role']==='observer'?'selected':''?>>Наблюдатель</option></select><button class="link-button">Сохранить</button></form></td><td><span class="mini-status <?=$a['is_active']?'mini-active':'mini-disabled'?>"><?=$a['is_active']?'Активен':'Отключён'?></span></td><td><?=e(format_datetime($a['last_login_at']))?></td><td><div class="row-actions"><form method="post"><?=csrf_field()?><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?=(int)$a['id']?>"><button class="link-button"><?=$a['is_active']?'Отключить':'Включить'?></button></form><details class="inline-details"><summary>Пароль</summary><form method="post" class="inline-form"><?=csrf_field()?><input type="hidden" name="action" value="password"><input type="hidden" name="id" value="<?=(int)$a['id']?>"><input type="password" name="password" minlength="10" required><button class="link-button">Изменить</button></form></details></div></td></tr><?php endforeach;?></tbody></table></div></section></div></section>
<?php require dirname(__DIR__).'/partials/footer.php';?>
